     1→// Test Results Aggregator — file-based app entry point
     2→// Usage: dotnet run aggregate.cs [directory] [--output <file>]
     3→//
     4→// Parses all .xml and .json test result files in the given directory,
     5→// aggregates results across the matrix, detects flaky tests, and outputs
     6→// a Markdown summary suitable for $GITHUB_STEP_SUMMARY.
     7→//
     8→// Examples:
     9→//   dotnet run aggregate.cs fixtures/
    10→//   dotnet run aggregate.cs fixtures/ --output summary.md
    11→
    12→using TestAggregator.Aggregation;
    13→using TestAggregator.Parsers;
    14→using TestAggregator.Reporting;
    15→
    16→// ── Parse CLI arguments ──────────────────────────────────────────────────────
    17→
    18→string directory = ".";
    19→string? outputFile = null;
    20→
    21→for (int i = 0; i < args.Length; i++)
    22→{
    23→    if (args[i] == "--output" && i + 1 < args.Length)
    24→    {
    25→        outputFile = args[++i];
    26→    }
    27→    else if (!args[i].StartsWith("--"))
    28→    {
    29→        directory = args[i];
    30→    }
    31→}
    32→
    33→if (!Directory.Exists(directory))
    34→{
    35→    Console.Error.WriteLine($"Error: Directory not found: {directory}");
    36→    Environment.Exit(1);
    37→}
    38→
    39→// ── Discover and parse all test result files ─────────────────────────────────
    40→
    41→var parsers = new ITestResultParser[] { new JUnitXmlParser(), new JsonTestResultParser() };
    42→
    43→var files = Directory.GetFiles(directory, "*.*", SearchOption.TopDirectoryOnly)
    44→    .Where(f => parsers.Any(p => p.CanParse(f)))
    45→    .OrderBy(f => f)
    46→    .ToList();
    47→
    48→if (files.Count == 0)
    49→{
    50→    Console.Error.WriteLine($"Warning: No test result files found in: {directory}");
    51→    Console.Error.WriteLine("  Supported formats: .xml (JUnit), .json");
    52→}
    53→
    54→var runs = new List<TestAggregator.Models.TestRun>();
    55→
    56→foreach (var file in files)
    57→{
    58→    var parser = parsers.First(p => p.CanParse(file));
    59→    try
    60→    {
    61→        var run = parser.Parse(file);
    62→        runs.Add(run);
    63→        Console.WriteLine($"  Parsed: {Path.GetFileName(file)} ({run.Suites.Sum(s => s.TestCases.Count)} tests)");
    64→    }
    65→    catch (Exception ex)
    66→    {
    67→        Console.Error.WriteLine($"  Error parsing {file}: {ex.Message}");
    68→    }
    69→}
    70→
    71→// ── Aggregate and report ──────────────────────────────────────────────────────
    72→
    73→var aggregator = new TestResultAggregator();
    74→var result = aggregator.Aggregate(runs);
    75→
    76→var reporter = new MarkdownReporter();
    77→var markdown = reporter.Generate(result);
    78→
    79→// Output to stdout and optionally to a file
    80→Console.WriteLine();
    81→Console.WriteLine(markdown);
    82→
    83→if (outputFile is not null)
    84→{
    85→    File.WriteAllText(outputFile, markdown);
    86→    Console.WriteLine($"Summary written to: {outputFile}");
    87→}
    88→
    89→// Print a compact CLI summary
    90→Console.WriteLine($"Results: {result.TotalPassed} passed, {result.TotalFailed} failed, " +
    91→    $"{result.TotalSkipped} skipped across {runs.Count} file(s).");
    92→
    93→if (result.FlakyTests.Count > 0)
    94→{
    95→    Console.WriteLine($"Flaky tests detected: {result.FlakyTests.Count}");
    96→    foreach (var f in result.FlakyTests)
    97→        Console.WriteLine($"  - {f.ClassName}.{f.Name} ({f.PassCount}P/{f.FailCount}F)");
    98→}
    99→
   100→// Exit non-zero if any tests failed (useful for CI)
   101→Environment.Exit(result.TotalFailed > 0 || result.TotalError > 0 ? 1 : 0);
   102→

