     1→// TDD Wave 4: Aggregator tests
     2→// Written before TestResultAggregator exists — drives implementation of totals and flaky detection.
     3→
     4→using TestAggregator.Aggregation;
     5→using TestAggregator.Models;
     6→using Xunit;
     7→
     8→namespace TestAggregator.Tests;
     9→
    10→public class AggregatorTests
    11→{
    12→    private static TestRun MakeRun(string file, params TestCase[] cases)
    13→    {
    14→        var suite = new TestSuite("Suite", cases, file);
    15→        return new TestRun(file, "junit-xml", [suite]);
    16→    }
    17→
    18→    private static TestCase Passed(string name, string cls = "Cls") =>
    19→        new(name, cls, "Suite", TestStatus.Passed, 0.1);
    20→
    21→    private static TestCase Failed(string name, string cls = "Cls") =>
    22→        new(name, cls, "Suite", TestStatus.Failed, 0.1, "Assert failed");
    23→
    24→    private static TestCase Skipped(string name, string cls = "Cls") =>
    25→        new(name, cls, "Suite", TestStatus.Skipped, 0.0);
    26→
    27→    // ── Totals ────────────────────────────────────────────────────────────────
    28→
    29→    [Fact]
    30→    public void Aggregate_EmptyRunList_ReturnsAllZeros()
    31→    {
    32→        var aggregator = new TestResultAggregator();
    33→        var result = aggregator.Aggregate([]);
    34→
    35→        Assert.Equal(0, result.TotalPassed);
    36→        Assert.Equal(0, result.TotalFailed);
    37→        Assert.Equal(0, result.TotalSkipped);
    38→        Assert.Equal(0, result.TotalError);
    39→        Assert.Equal(0.0, result.TotalDurationSeconds);
    40→        Assert.Empty(result.FlakyTests);
    41→    }
    42→
    43→    [Fact]
    44→    public void Aggregate_SingleRunAllPassed_ReturnsTotalPassed()
    45→    {
    46→        var aggregator = new TestResultAggregator();
    47→        var run = MakeRun("a.xml", Passed("T1"), Passed("T2"), Passed("T3"));
    48→
    49→        var result = aggregator.Aggregate([run]);
    50→
    51→        Assert.Equal(3, result.TotalPassed);
    52→        Assert.Equal(0, result.TotalFailed);
    53→    }
    54→
    55→    [Fact]
    56→    public void Aggregate_MultipleRuns_SumsTotalsAcrossRuns()
    57→    {
    58→        var aggregator = new TestResultAggregator();
    59→        var run1 = MakeRun("a.xml", Passed("T1"), Failed("T2"));
    60→        var run2 = MakeRun("b.xml", Passed("T3"), Passed("T4"), Skipped("T5"));
    61→
    62→        var result = aggregator.Aggregate([run1, run2]);
    63→
    64→        Assert.Equal(3, result.TotalPassed);
    65→        Assert.Equal(1, result.TotalFailed);
    66→        Assert.Equal(1, result.TotalSkipped);
    67→        Assert.Equal(5, result.TotalTests);
    68→    }
    69→
    70→    [Fact]
    71→    public void Aggregate_DurationsSummedAcrossAllRuns()
    72→    {
    73→        var aggregator = new TestResultAggregator();
    74→        // Create suites with known durations via TestCase durations
    75→        var cases1 = new[] { new TestCase("T1", "C", "S", TestStatus.Passed, 1.0) };
    76→        var cases2 = new[] { new TestCase("T2", "C", "S", TestStatus.Passed, 2.5) };
    77→        var suite1 = new TestSuite("S1", cases1, "a.xml");
    78→        var suite2 = new TestSuite("S2", cases2, "b.xml");
    79→        var run1 = new TestRun("a.xml", "junit-xml", [suite1]);
    80→        var run2 = new TestRun("b.xml", "junit-xml", [suite2]);
    81→
    82→        var result = aggregator.Aggregate([run1, run2]);
    83→
    84→        Assert.Equal(3.5, result.TotalDurationSeconds, precision: 5);
    85→    }
    86→
    87→    // ── Flaky detection ───────────────────────────────────────────────────────
    88→
    89→    [Fact]
    90→    public void Aggregate_TestPassesInOneRunFailsInAnother_IsFlaky()
    91→    {
    92→        var aggregator = new TestResultAggregator();
    93→        var run1 = MakeRun("a.xml", Passed("FlakeyTest", "MyClass"));
    94→        var run2 = MakeRun("b.xml", Failed("FlakeyTest", "MyClass"));
    95→
    96→        var result = aggregator.Aggregate([run1, run2]);
    97→
    98→        var flaky = Assert.Single(result.FlakyTests);
    99→        Assert.Equal("FlakeyTest", flaky.Name);
   100→        Assert.Equal("MyClass", flaky.ClassName);
   101→    }
   102→
   103→    [Fact]
   104→    public void Aggregate_FlakyTest_HasCorrectPassAndFailCounts()
   105→    {
   106→        var aggregator = new TestResultAggregator();
   107→        var run1 = MakeRun("a.xml", Passed("FlakyTest", "Cls"));
   108→        var run2 = MakeRun("b.xml", Failed("FlakyTest", "Cls"));
   109→        var run3 = MakeRun("c.xml", Passed("FlakyTest", "Cls"));
   110→
   111→        var result = aggregator.Aggregate([run1, run2, run3]);
   112→
   113→        var flaky = Assert.Single(result.FlakyTests);
   114→        Assert.Equal(2, flaky.PassCount);
   115→        Assert.Equal(1, flaky.FailCount);
   116→    }
   117→
   118→    [Fact]
   119→    public void Aggregate_FlakyTest_RecordsWhichFilesItFailedIn()
   120→    {
   121→        var aggregator = new TestResultAggregator();
   122→        var run1 = MakeRun("pass.xml", Passed("FlakyTest", "Cls"));
   123→        var run2 = MakeRun("fail.xml", Failed("FlakyTest", "Cls"));
   124→
   125→        var result = aggregator.Aggregate([run1, run2]);
   126→
   127→        var flaky = Assert.Single(result.FlakyTests);
   128→        Assert.Contains("fail.xml", flaky.FailingFiles);
   129→        Assert.DoesNotContain("pass.xml", flaky.FailingFiles);
   130→    }
   131→
   132→    [Fact]
   133→    public void Aggregate_TestFailsInAllRuns_IsNotFlaky()
   134→    {
   135→        var aggregator = new TestResultAggregator();
   136→        var run1 = MakeRun("a.xml", Failed("AlwaysFails", "Cls"));
   137→        var run2 = MakeRun("b.xml", Failed("AlwaysFails", "Cls"));
   138→
   139→        var result = aggregator.Aggregate([run1, run2]);
   140→
   141→        Assert.Empty(result.FlakyTests);
   142→    }
   143→
   144→    [Fact]
   145→    public void Aggregate_TestPassesInAllRuns_IsNotFlaky()
   146→    {
   147→        var aggregator = new TestResultAggregator();
   148→        var run1 = MakeRun("a.xml", Passed("AlwaysPasses", "Cls"));
   149→        var run2 = MakeRun("b.xml", Passed("AlwaysPasses", "Cls"));
   150→
   151→        var result = aggregator.Aggregate([run1, run2]);
   152→
   153→        Assert.Empty(result.FlakyTests);
   154→    }
   155→
   156→    [Fact]
   157→    public void Aggregate_DifferentClassSameName_NotConsideredSameTest()
   158→    {
   159→        // Tests with the same name in different classes should not be conflated
   160→        var aggregator = new TestResultAggregator();
