     1→using System.Xml.Linq;
     2→using TestAggregator.Models;
     3→
     4→namespace TestAggregator.Parsers;
     5→
     6→/// <summary>
     7→/// Parses JUnit XML test result files.
     8→/// Handles both &lt;testsuite&gt; and &lt;testsuites&gt; root elements.
     9→/// Uses System.Xml.Linq (in-box, no NuGet required).
    10→/// </summary>
    11→public class JUnitXmlParser : ITestResultParser
    12→{
    13→    public bool CanParse(string filePath) =>
    14→        Path.GetExtension(filePath).Equals(".xml", StringComparison.OrdinalIgnoreCase);
    15→
    16→    public TestRun Parse(string filePath)
    17→    {
    18→        var doc = XDocument.Load(filePath);
    19→        var root = doc.Root ?? throw new InvalidDataException($"Empty XML document: {filePath}");
    20→
    21→        // Support both <testsuites> wrapper and bare <testsuite>
    22→        IEnumerable<XElement> suiteElements = root.Name.LocalName == "testsuites"
    23→            ? root.Elements("testsuite")
    24→            : new[] { root };  // Single suite — wrap in a one-element array
    25→
    26→        var suites = suiteElements
    27→            .Select(el => ParseSuite(el, filePath))
    28→            .ToList();
    29→
    30→        return new TestRun(filePath, "junit-xml", suites);
    31→    }
    32→
    33→    private static TestSuite ParseSuite(XElement el, string sourceFile)
    34→    {
    35→        var suiteName = el.Attribute("name")?.Value ?? "Unknown";
    36→
    37→        var cases = el.Elements("testcase")
    38→            .Select(tc => ParseTestCase(tc, suiteName))
    39→            .ToList();
    40→
    41→        return new TestSuite(suiteName, cases, sourceFile);
    42→    }
    43→
    44→    private static TestCase ParseTestCase(XElement el, string suiteName)
    45→    {
    46→        var name = el.Attribute("name")?.Value ?? "Unknown";
    47→        var className = el.Attribute("classname")?.Value ?? suiteName;
    48→        var duration = double.TryParse(
    49→            el.Attribute("time")?.Value,
    50→            System.Globalization.NumberStyles.Any,
    51→            System.Globalization.CultureInfo.InvariantCulture,
    52→            out var d) ? d : 0.0;
    53→
    54→        // Determine status by checking child elements
    55→        if (el.Element("failure") is XElement failure)
    56→        {
    57→            return new TestCase(
    58→                Name: name,
    59→                ClassName: className,
    60→                SuiteName: suiteName,
    61→                Status: TestStatus.Failed,
    62→                DurationSeconds: duration,
    63→                ErrorMessage: failure.Attribute("message")?.Value ?? failure.Value.Trim(),
    64→                ErrorType: failure.Attribute("type")?.Value
    65→            );
    66→        }
    67→
    68→        if (el.Element("error") is XElement error)
    69→        {
    70→            return new TestCase(
    71→                Name: name,
    72→                ClassName: className,
    73→                SuiteName: suiteName,
    74→                Status: TestStatus.Error,
    75→                DurationSeconds: duration,
    76→                ErrorMessage: error.Attribute("message")?.Value ?? error.Value.Trim(),
    77→                ErrorType: error.Attribute("type")?.Value
    78→            );
    79→        }
    80→
    81→        if (el.Element("skipped") is not null)
    82→        {
