     1→using System.Text.Json;
     2→using TestAggregator.Models;
     3→
     4→namespace TestAggregator.Parsers;
     5→
     6→/// <summary>
     7→/// Parses JSON test result files in our custom schema:
     8→/// { "suiteName": "...", "testCases": [ { "name", "className", "status", "duration", "errorMessage?" } ] }
     9→/// Uses System.Text.Json (in-box, no NuGet required).
    10→/// </summary>
    11→public class JsonTestResultParser : ITestResultParser
    12→{
    13→    public bool CanParse(string filePath) =>
    14→        Path.GetExtension(filePath).Equals(".json", StringComparison.OrdinalIgnoreCase);
    15→
    16→    public TestRun Parse(string filePath)
    17→    {
    18→        var json = File.ReadAllText(filePath);
    19→        using var doc = JsonDocument.Parse(json);
    20→        var root = doc.RootElement;
    21→
    22→        var suiteName = root.TryGetProperty("suiteName", out var snProp)
    23→            ? snProp.GetString() ?? "Unknown"
    24→            : Path.GetFileNameWithoutExtension(filePath);
    25→
    26→        var cases = new List<TestCase>();
    27→
    28→        if (root.TryGetProperty("testCases", out var tcArray))
    29→        {
    30→            foreach (var tc in tcArray.EnumerateArray())
    31→            {
    32→                cases.Add(ParseTestCase(tc, suiteName));
    33→            }
    34→        }
    35→
    36→        var suite = new TestSuite(suiteName, cases, filePath);
    37→        return new TestRun(filePath, "json", [suite]);
    38→    }
    39→
    40→    private static TestCase ParseTestCase(JsonElement el, string suiteName)
    41→    {
    42→        var name = el.TryGetProperty("name", out var n) ? n.GetString() ?? "Unknown" : "Unknown";
    43→        var className = el.TryGetProperty("className", out var cn) ? cn.GetString() ?? suiteName : suiteName;
    44→        var duration = el.TryGetProperty("duration", out var d) ? d.GetDouble() : 0.0;
    45→        var errorMessage = el.TryGetProperty("errorMessage", out var em) ? em.GetString() : null;
    46→
    47→        var statusStr = el.TryGetProperty("status", out var s) ? s.GetString() ?? "passed" : "passed";
    48→        var status = statusStr.ToLowerInvariant() switch
    49→        {
    50→            "passed" or "pass" or "ok" => TestStatus.Passed,
    51→            "failed" or "fail" or "failure" => TestStatus.Failed,
    52→            "skipped" or "skip" or "pending" or "ignored" => TestStatus.Skipped,
    53→            "error" => TestStatus.Error,
    54→            _ => throw new InvalidDataException($"Unknown test status '{statusStr}'")
    55→        };
    56→
    57→        return new TestCase(name, className, suiteName, status, duration, errorMessage);
    58→    }
    59→}
