     1→using TestAggregator.Models;
     2→
     3→namespace TestAggregator.Aggregation;
     4→
     5→/// <summary>
     6→/// Aggregates test runs across a matrix build.
     7→///
     8→/// Flakiness algorithm:
     9→///   For each unique (ClassName, TestName) pair, track pass/fail counts across all runs.
    10→///   A test is flaky when passCount > 0 AND failCount > 0.
    11→///
    12→/// The composite key uses '|' as separator — safe because JUnit class names use
    13→/// dot-separated package notation which never contains pipes.
    14→/// </summary>
    15→public class TestResultAggregator : ITestResultAggregator
    16→{
    17→    public AggregatedResult Aggregate(IReadOnlyList<TestRun> runs)
    18→    {
    19→        int passed = 0, failed = 0, skipped = 0, error = 0;
    20→        double duration = 0.0;
    21→
    22→        // Key: "ClassName|TestName" → (passCount, failCount, failingFiles)
    23→        var tracking = new Dictionary<string, (int pass, int fail, List<string> failFiles)>();
    24→
    25→        foreach (var run in runs)
    26→        {
    27→            foreach (var suite in run.Suites)
    28→            {
    29→                foreach (var tc in suite.TestCases)
    30→                {
    31→                    duration += tc.DurationSeconds;
    32→
    33→                    switch (tc.Status)
    34→                    {
    35→                        case TestStatus.Passed:  passed++;  break;
    36→                        case TestStatus.Failed:  failed++;  break;
    37→                        case TestStatus.Skipped: skipped++; break;
    38→                        case TestStatus.Error:   error++;   break;
    39→                    }
    40→
    41→                    // Only track Passed/Failed for flakiness — Skipped/Error are excluded
    42→                    if (tc.Status is not (TestStatus.Passed or TestStatus.Failed or TestStatus.Error))
    43→                        continue;
    44→
    45→                    var key = $"{tc.ClassName}|{tc.Name}";
    46→                    if (!tracking.TryGetValue(key, out var entry))
    47→                        entry = (0, 0, new List<string>());
    48→
    49→                    if (tc.Status == TestStatus.Passed)
    50→                    {
    51→                        tracking[key] = (entry.pass + 1, entry.fail, entry.failFiles);
    52→                    }
    53→                    else // Failed or Error
    54→                    {
    55→                        entry.failFiles.Add(run.SourceFile);
    56→                        tracking[key] = (entry.pass, entry.fail + 1, entry.failFiles);
    57→                    }
    58→                }
    59→            }
    60→        }
    61→
    62→        var flakyTests = tracking
    63→            .Where(kv => kv.Value.pass > 0 && kv.Value.fail > 0)
    64→            .Select(kv =>
    65→            {
    66→                var parts = kv.Key.Split('|', 2);
    67→                return new FlakyTest(
    68→                    Name: parts[1],
    69→                    ClassName: parts[0],
    70→                    PassCount: kv.Value.pass,
    71→                    FailCount: kv.Value.fail,
    72→                    FailingFiles: kv.Value.failFiles.AsReadOnly()
    73→                );
    74→            })
    75→            .OrderBy(f => f.ClassName)
    76→            .ThenBy(f => f.Name)
    77→            .ToList();
    78→
    79→        return new AggregatedResult(passed, failed, skipped, error, duration, flakyTests, runs);
    80→    }
    81→}
    82→

