     6→/// <summary>
     7→/// Generates a GitHub Actions-compatible Markdown summary from an AggregatedResult.
     8→/// Output is suitable for writing to $GITHUB_STEP_SUMMARY.
     9→///
    10→/// Sections:
    11→///   ## Test Results Summary   — overall totals table
    12→///   ### Results by File       — per-run breakdown table
    13→///   ### Flaky Tests           — only present when flaky tests are detected
    14→/// </summary>
    15→public class MarkdownReporter
    16→{
    17→    public string Generate(AggregatedResult result)
    18→    {
    19→        var sb = new StringBuilder();
    20→
    21→        AppendSummarySection(sb, result);
    22→        AppendResultsByFileSection(sb, result);
    23→
    24→        if (result.FlakyTests.Count > 0)
    25→            AppendFlakyTestsSection(sb, result);
    26→
    27→        return sb.ToString();
    28→    }
    29→
    30→    private static void AppendSummarySection(StringBuilder sb, AggregatedResult r)
    31→    {
    32→        sb.AppendLine("## Test Results Summary");
    33→        sb.AppendLine();
    34→
    35→        // Status badge line
    36→        var status = r.TotalFailed > 0 || r.TotalError > 0 ? "FAILED" : "PASSED";
    37→        sb.AppendLine($"> **Status: {status}**");
    38→        sb.AppendLine();
    39→
    40→        sb.AppendLine("| Metric | Value |");
    41→        sb.AppendLine("|--------|-------|");
    42→        sb.AppendLine($"| Total Tests | {r.TotalTests} |");
    43→        sb.AppendLine($"| Passed | {r.TotalPassed} |");
    44→        sb.AppendLine($"| Failed | {r.TotalFailed} |");
    45→        sb.AppendLine($"| Skipped | {r.TotalSkipped} |");
    46→        sb.AppendLine($"| Errors | {r.TotalError} |");
    47→        sb.AppendLine($"| Total Duration | {r.TotalDurationSeconds:F2}s |");
    48→        sb.AppendLine($"| Source Files | {r.Runs.Count} |");
    49→        sb.AppendLine($"| Flaky Tests | {r.FlakyTests.Count} |");
    50→        sb.AppendLine();
    51→    }
    52→
    53→    private static void AppendResultsByFileSection(StringBuilder sb, AggregatedResult r)
    54→    {
    55→        if (r.Runs.Count == 0) return;
    56→
    57→        sb.AppendLine("### Results by File");
    58→        sb.AppendLine();
    59→        sb.AppendLine("| File | Format | Tests | Passed | Failed | Skipped | Duration |");
    60→        sb.AppendLine("|------|--------|-------|--------|--------|---------|----------|");
    61→
    62→        foreach (var run in r.Runs)
    63→        {
    64→            var allCases = run.Suites.SelectMany(s => s.TestCases).ToList();
    65→            var runPassed = allCases.Count(t => t.Status == TestStatus.Passed);
    66→            var runFailed = allCases.Count(t => t.Status is TestStatus.Failed or TestStatus.Error);
    67→            var runSkipped = allCases.Count(t => t.Status == TestStatus.Skipped);
    68→            var runDuration = allCases.Sum(t => t.DurationSeconds);
    69→            var fileName = Path.GetFileName(run.SourceFile);
    70→
    71→            sb.AppendLine($"| {fileName} | {run.Format} | {allCases.Count} | {runPassed} | {runFailed} | {runSkipped} | {runDuration:F2}s |");
    72→        }
    73→
    74→        sb.AppendLine();
    75→    }
    76→
    77→    private static void AppendFlakyTestsSection(StringBuilder sb, AggregatedResult r)
    78→    {
    79→        sb.AppendLine("### Flaky Tests");
    80→        sb.AppendLine();
    81→        sb.AppendLine("> Tests that passed in some runs and failed in others.");
    82→        sb.AppendLine();
    83→        sb.AppendLine("| Test | Class | Passes | Failures | Failed In |");
    84→        sb.AppendLine("|------|-------|--------|----------|-----------|");
    85→
    86→        foreach (var f in r.FlakyTests)
    87→        {
    88→            var failingFiles = string.Join(", ", f.FailingFiles.Select(Path.GetFileName));
    89→            sb.AppendLine($"| {f.Name} | {f.ClassName} | {f.PassCount} | {f.FailCount} | {failingFiles} |");
    90→        }
    91→
    92→        sb.AppendLine();
    93→    }
    94→}
